// ═══════════════════════════════════════════════════════════════
// TEMPLATE SANITIZADO — sistema_expirar_prereservas v1
// ═══════════════════════════════════════════════════════════════
// Este JSON es un template genérico para importar en n8n.
// No contiene credenciales, IDs de Sheet ni IDs de workflow reales.
//
// Antes de importar, reemplazar:
//   __SHEETS_ID__                              → ID del Google Sheet del entorno
//   __CREDENTIAL_ID__                          → ID de la credencial OAuth en n8n
//   __CREDENTIAL_NAME__                        → Nombre de la credencial OAuth en n8n
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__  → ID de db_recalcular_disponibilidad
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__ → Nombre de db_recalcular_disponibilidad
//
// SCHEDULE TRIGGER:
// Cron default: '0 3 * * *' = una vez por día a las 03:00 UTC.
// Para dos veces por día: '0 3,15 * * *'.
// En DEV/TEST: mantener workflow INACTIVO y usar Manual Trigger.
// En producción: activar el workflow cuando se quiera automatizar.
// ═══════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ALCANCE v1:
// ✅ Detecta PRE_RESERVAS con estado = pendiente_pago
//    y expira_en <= now, y las marca como vencidas.
// ✅ Soporte dry_run para detectar sin escribir.
// ✅ Solo actúa si hay PRE_RESERVAS vencidas (no llama
//    a db_recalcular_disponibilidad si expiradas = 0).
// ✅ Escribe LOG_CAMBIOS por cada PRE_RESERVA vencida.
//
// ❌ FUERA DE ALCANCE en v1:
//    - No toca pago_en_revision (aunque expira_en esté vencido)
//    - No toca convertida, cancelada, vencida ni cualquier
//      otro estado distinto de pendiente_pago
//    - No toca PAGOS, RESERVAS, CONSULTAS
//    - No toca DISPONIBILIDAD_CACHE directamente
//    - No envía WhatsApp ni notificaciones
//    - No usa IA ni MercadoPago
//    - No elimina filas
//
// ⚠️  SCHEDULE TRIGGER
// Cron default: '0 3 * * *' = una vez por día a las 03:00 UTC.
// Para dos veces por día: cambiar a '0 3,15 * * *'.
// Para activarlo: Settings del workflow → Active → ON.
// En DEV/TEST dejarlo inactivo y ejecutar manualmente.
//
// ⚠️  SHEETS_ID — __ENTORNO__
// Valor actual: __SHEETS_ID__
//
// ⚠️  WORKFLOW ID — db_recalcular_disponibilidad
// __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__ → ID: __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID = '__SHEETS_ID__'; // __ENTORNO__

const raw          = $input.first()?.json ?? {};
const source_event = String(raw.source_event ?? 'scheduled_expiration').trim();
const dry_run      = raw.dry_run === true || String(raw.dry_run).toLowerCase() === 'true';

return [{ json: {
  SHEETS_ID,
  source_event,
  dry_run,
  ts_inicio: new Date().toISOString()
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Detectar Vencidas
// ═══════════════════════════════════════════════════════════════
// Filtra PRE_RESERVAS que cumplen TODAS estas condiciones:
//   - estado = 'pendiente_pago' (exacto)
//   - expira_en es válido y parseable
//   - expira_en <= ahora
//
// Ignora sin error ni log:
//   - estado ≠ pendiente_pago (incluido pago_en_revision)
//   - expira_en vacío, inválido o no parseable
//
// Si dry_run = true: retorna el análisis sin marcar nada.
// ═══════════════════════════════════════════════════════════════

const inputData   = $('Resolver Input').first().json;
const ahora       = new Date();
const ahoraTsMs   = ahora.getTime();

function parseTimestamp(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) return isNaN(val.getTime()) ? null : val;
  if (typeof val === 'number') {
    // Serial de Sheets (días desde 1899-12-30)
    if (val < 200000) {
      const d = new Date(Date.UTC(1899, 11, 30) + val * 86400000);
      return isNaN(d.getTime()) ? null : d;
    }
    // Unix ms
    const d = new Date(val);
    return isNaN(d.getTime()) ? null : d;
  }
  const s = String(val).trim();
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

const rows = ($('Agg PRE_RESERVAS').first()?.json?.data ?? [])
  .filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));

const vencidas = [];

for (const row of rows) {
  // Solo procesar pendiente_pago
  if (String(row.estado ?? '').trim() !== 'pendiente_pago') continue;

  // expira_en debe ser válido y parseable
  const expiraTs = parseTimestamp(row.expira_en);
  if (!expiraTs) continue; // vacío o inválido → ignorar

  // expira_en debe haber pasado
  if (expiraTs.getTime() > ahoraTsMs) continue;

  vencidas.push({
    id_prereserva: parseInt(String(row.id_prereserva), 10),
    id_cabana:     row.id_cabana     ?? '',
    fecha_in:      row.fecha_in      ?? '',
    fecha_out:     row.fecha_out     ?? '',
    expira_en:     row.expira_en,
    estado_previo: 'pendiente_pago',
    estado_nuevo:  'vencida',
    updated_at:    ahora.toISOString()
  });
}

return [{ json: {
  vencidas,
  expiradas: vencidas.length,
  dry_run:   inputData.dry_run,
  source_event: inputData.source_event
}}];

// No hay PRE_RESERVAS vencidas — salida limpia sin tocar nada
return [{ json: {
  ok:              true,
  expiradas:       0,
  dry_run:         $('Detectar Vencidas').first().json.dry_run,
  recalculo_cache: 'skipped',
  mensaje:         'No hay pre-reservas vencidas para expirar'
}}];

// Dry run — devolver análisis sin escribir nada
const d = $input.first().json;
return [{ json: {
  ok:           true,
  dry_run:      true,
  expirarian:   d.expiradas,
  ids_prereserva: d.vencidas.map(v => v.id_prereserva),
  detalle:      d.vencidas.map(v => ({
    id_prereserva: v.id_prereserva,
    id_cabana:     v.id_cabana,
    fecha_in:      v.fecha_in,
    fecha_out:     v.fecha_out,
    expira_en:     v.expira_en
  })),
  mensaje: 'Dry run: no se escribieron cambios'
}}];

// Preparar items para Actualizar PRE_RESERVAS
// Un item por PRE_RESERVA vencida
const d = $input.first().json;
return d.vencidas.map(v => ({ json: {
  id_prereserva: v.id_prereserva,
  estado:        'vencida',
  updated_at:    v.updated_at
}}));

// Preparar filas de LOG_CAMBIOS — una por PRE_RESERVA vencida
const d = $('Detectar Vencidas').first().json;
const ahora = new Date();

return d.vencidas.map(v => ({ json: {
  id_log:           `LOG-EXPIRA-${v.id_prereserva}-${ahora.getTime()}`,
  fecha_hora:        v.updated_at,
  tabla_afectada:   'PRE_RESERVAS',
  id_registro:      String(v.id_prereserva),
  campo_modificado: 'estado',
  valor_anterior:   'pendiente_pago',
  valor_nuevo:      'vencida',
  modificado_por:   'n8n',
  source_event:     d.source_event,
  nivel:            'info',
  detalle: JSON.stringify({
    id_prereserva: v.id_prereserva,
    id_cabana:     v.id_cabana,
    fecha_in:      v.fecha_in,
    fecha_out:     v.fecha_out,
    expira_en:     v.expira_en
  })
}}));

// ═══════════════════════════════════════════════════════════════
// NODO FINAL — Resumen
// ═══════════════════════════════════════════════════════════════
// continueOnFail = true garantiza que siempre llega aquí.
// Si el recálculo falló, las PRE_RESERVAS ya fueron actualizadas
// y los LOGs ya fueron escritos. Solo la cache puede estar
// desactualizada. Acción: ejecutar recálculo manual.
// ═══════════════════════════════════════════════════════════════

const d = $('Detectar Vencidas').first().json;

const recalculoOutput = $('Ejecutar Recalculo Final').first()?.json ?? {};
const recalculo_fallo = !!recalculoOutput.error || recalculoOutput.ok === false;

return [{ json: {
  ok:              true,
  expiradas:       d.expiradas,
  ids_prereserva:  d.vencidas.map(v => v.id_prereserva),
  dry_run:         false,
  recalculo_cache: recalculo_fallo ? 'warning' : 'ok',
  recalculo_error: recalculo_fallo
    ? 'db_recalcular_disponibilidad falló después de expirar las pre-reservas. Cache puede estar desactualizada. Ejecutar recálculo manual.'
    : null,
  mensaje: 'Pre-reservas vencidas expiradas correctamente'
}}];
